from flask import Flask, request, jsonify
import pickle
import os
import time

app = Flask(__name__)
CACHE_DIR = 'cache'
if not os.path.exists(CACHE_DIR):
    os.makedirs(CACHE_DIR)

def cache_key(func_name, *args, **kwargs):
    return f"{func_name}_{hash(args)}_{hash(frozenset(kwargs.items()))}"

def get_cached_response(func, *args, **kwargs):
    key = cache_key(func.__name__, args, kwargs)
    cache_file = os.path.join(CACHE_DIR, key)
    
    if os.path.exists(cache_file):
        with open(cache_file, 'rb') as f:
            data = pickle.load(f)
            if time.time() - data['timestamp'] < data['ttl']:
                return data['response']
    
    response = func(*args, **kwargs)
    cache_data = {
        'response': response,
        'timestamp': time.time(),
        'ttl': 3600  # Cache for 1 hour
    }
    with open(cache_file, 'wb') as f:
        pickle.dump(cache_data, f)
    
    return response

@app.route('/api/data', methods=['GET'])
def get_data():
    data = get_cached_response(expensive_api_call, request.args.get('param'))
    return jsonify(data)

def expensive_api_call(param):
    # Simulate an expensive API call
    time.sleep(2)
    return {'data': param, 'metadata': {'timestamp': time.time()}}

if __name__ == '__main__':
    app.run(debug=True)